package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = CSVFormat.newFormat(',').withQuote('"').withIgnoreEmptyLines(false).withTrim(true)
                .withRecordSeparator("\r\n");
    }

    @Test
    public void testGetTrim() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        Method method = CSVFormat.class.getDeclaredMethod("getTrim");
        method.setAccessible(true);

        // When
        boolean result = (boolean) method.invoke(csvFormat);

        // Then
        assertTrue(result);
    }

    @Test
    public void testWithTrim() {
        // Given
        assertTrue(csvFormat.getTrim());

        // When
        csvFormat = csvFormat.withTrim(false);

        // Then
        assertFalse(csvFormat.getTrim());
    }

    @Test
    public void testWithTrimUsingReflection() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Given
        Method method = CSVFormat.class.getDeclaredMethod("withTrim", boolean.class);
        method.setAccessible(true);

        // When
        csvFormat = (CSVFormat) method.invoke(csvFormat, false);

        // Then
        assertFalse(csvFormat.getTrim());
    }

    // Add more test cases for other methods if needed

}
